mapper.select:
SELECT t.id, t.title, t.description, t.groupid, t.priority, t.status, t.duedate, t.completedtime, t.createtime, t.updatetime, g.name as groupname, g.color as groupcolor FROM t_tasks t LEFT JOIN t_groups g ON t.groupid = g.id AND g.deleted = 0 WHERE t.deleted = 0 AND t.userid = #{userid}
AND t.status = #{status}
ORDER BY t.priority DESC, t.duedate ASC, t.createtime DESC

